script:
frappe.ui.form.on('Sales Order Item', {
	custom_thickness(frm, cdt, cdn) {
		set_ss_coil_dimension(cdt, cdn);
	},
	custom_width(frm, cdt, cdn) {
		set_ss_coil_dimension(cdt, cdn);
	},
	custom_length(frm, cdt, cdn) {
		set_ss_coil_dimension(cdt, cdn);
	},
	form_render(frm, cdt, cdn) {
		set_ss_coil_dimension(cdt, cdn);
	}
});

frappe.ui.form.on('Sales Order', {
	validate(frm) {
		(frm.doc.items || []).forEach((d) => set_ss_coil_dimension(d.doctype, d.name));
	}
});

function set_ss_coil_dimension(cdt, cdn) {
	const row = locals[cdt] && locals[cdt][cdn];
	if (!row) return;

	const t = row.custom_thickness == null ? '' : String(row.custom_thickness).trim();
	const w = row.custom_width == null ? '' : String(row.custom_width).trim();
	const l = row.custom_length == null ? '' : String(row.custom_length).trim();

	const parts = [t, w, l].filter(Boolean);
	frappe.model.set_value(cdt, cdn, 'custom_dimension', parts.join(' x '));
}

frappe.ui.form.on('Stock Entry Detail', {
	custom_thickness(frm, cdt, cdn) {
		set_ss_stock_dimension(cdt, cdn);
